# Regenerated by Claude Code. Reviewed and edited by George Chacko
# Table: planted node experiment results, P5 vs PS5 across 5 conditions
# Rank 1 = planted node achieves max in_degree among all agent-type nodes

rm(list = ls())
library(data.table)

# ── Paths & thresholds ────────────────────────────────────────────────────────
root_dir <- "/projects/illinois/eng/cs/chackoge/illinoiscomputes/abm/v6/chacko/planted_exps"
out_dir  <- root_dir

BSL_THRESH_999  <- 1707
BSL_THRESH_9999 <- 9018

# ── Condition mapping ─────────────────────────────────────────────────────────
cond_dirs <- c(
  "Fit-dom restr."   = "fit_dom_restr",
  "Fit-dom unrestr." = "fit_dom_unrestr",
  "Reference"        = "historical_reference",
  "Soc-dom restr."   = "soc_dom_restr",
  "Soc-dom unrestr." = "soc_dom_unrestr"
)

# ── Compute stats for one series ──────────────────────────────────────────────
compute_stats <- function(series) {
  series_dir <- file.path(root_dir, paste0(series, "_series"))

  rbindlist(lapply(names(cond_dirs), function(label) {
    stem <- cond_dirs[label]
    dirs <- paste0(series, stem, "_r", 0:2)

    # Pool planted nodes across replicates for median and % stats
    pool <- rbindlist(lapply(dirs, function(d) {
      f  <- file.path(series_dir, d, "output", "nodelist.csv")
      dt <- fread(f, select = c("type", "planted_nodes_line_number", "in_degree"))
      dt[planted_nodes_line_number != -1, .(in_degree)]
    }))

    # Rank-1: per replicate, does best planted node == max agent in_degree?
    rank1 <- sum(sapply(dirs, function(d) {
      f  <- file.path(series_dir, d, "output", "nodelist.csv")
      dt <- fread(f, select = c("type", "planted_nodes_line_number", "in_degree"))
      max_planted <- max(dt[planted_nodes_line_number != -1, in_degree])
      max_agent   <- max(dt[type == "agent", in_degree])
      max_planted == max_agent
    }))

    x <- pool$in_degree
    data.table(
      series   = series,
      cond     = label,
      median   = median(x),
      top_01   = round(100 * mean(x >= BSL_THRESH_999)),
      top_001  = round(100 * mean(x >= BSL_THRESH_9999)),
      rank1    = rank1
    )
  }))
}

cat("Computing P5...\n");  p5  <- compute_stats("p5")
cat("Computing PS5...\n"); ps5 <- compute_stats("ps5")

print(p5); print(ps5)

# ── Format display columns ────────────────────────────────────────────────────
fmt <- function(dt) {
  dt[, .(
    cond,
    median  = formatC(round(median),  format = "d", big.mark = ","),
    top_01  = paste0(top_01,  "\\%"),
    top_001 = paste0(top_001, "\\%"),
    rank1   = as.character(rank1)
  )]
}

p5f  <- fmt(p5)
ps5f <- fmt(ps5)

# ── Build LaTeX ───────────────────────────────────────────────────────────────
rows <- sapply(seq_len(nrow(p5f)), function(i) {
  paste0(
    sprintf("%-20s", p5f$cond[i]), " & ",
    p5f$median[i],  " & ", p5f$top_01[i],  " & ",
    p5f$top_001[i], " & ", p5f$rank1[i],   " & ",
    ps5f$median[i], " & ", ps5f$top_01[i], " & ",
    ps5f$top_001[i]," & ", ps5f$rank1[i],
    " \\\\"
  )
})

latex <- c(
