  "\\label{tab:p5_ps5_combined}",
  "\\setlength{\\tabcolsep}{4pt}",
  "\\begin{tabular}{lrrrr rrrr}",
  "\\toprule",
  "& \\multicolumn{4}{c}{P5 (simultaneous)} & \\multicolumn{4}{c}{PS5 (staggered)} \\\\",
  "\\cmidrule(lr){2-5} \\cmidrule(lr){6-9}",
  "Condition & Median & Top 0.1\\% & Top 0.01\\% & Rank 1 & Median & Top 0.1\\% & Top 0.01\\% & Rank 1 \\\\",
  "\\midrule",
  rows,
  "\\bottomrule",
  "\\end{tabular}",
  "\\end{table}"
